// Install — cache everything
self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => {
            console.log('[SW] Caching', CACHE_URLS.length, 'files');
            // Cache in batches to avoid timeout
            const batch = (arr, size) => Array.from({length:Math.ceil(arr.length/size)}, (_,i) => arr.slice(i*size,i*size+size));
            const batches = batch(CACHE_URLS, 20);
            return batches.reduce((p, b) => p.then(() =>
                Promise.allSettled(b.map(u => cache.add(u).catch(err => console.log('[SW] Cache miss:', u, err))))
            ), Promise.resolve());
        })
    );
    // NOTE: intentionally NOT calling self.skipWaiting() here. Activation is
    // page-controlled (mc-sw-update.js posts 'skipWaiting' only when no workout
    // is in progress) so a new build never force-reloads someone mid-set.
});

// Activate — remove ALL old caches and take control. The page-side reload is
// driven by mc-sw-update.js's 'controllerchange' handler (which guards against
// reloading mid-workout), so we do NOT force-navigate tabs here.
self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys()
            .then(keys => Promise.all(
                keys.filter(k => k !== CACHE_NAME).map(k => {
                    console.log('[SW] Removing old cache:', k);
                    return caches.delete(k);
                })
            ))
            .then(() => self.clients.claim())
    );
});

// Offline fallback page (shared by the HTML + asset handlers).
function offlinePage(msg) {
    return new Response(
        '<html><body style="background:#0a0a0a;color:#fff;font-family:sans-serif;text-align:center;padding:60px 20px"><h2 style="color:#d4af37">MC Training</h2><p style="color:#9ca3af;margin-top:12px">' +
        (msg || 'You are offline.') +
        '</p><a href="/" style="display:inline-block;margin-top:20px;color:#d4af37">← Home</a></body></html>',
        { headers: { 'Content-Type': 'text/html' } }
    );
}

// Offline fallback for a non-HTML asset that was never cached.
function assetOfflinePage() {
    return new Response(
        '<html><body style="background:#0a0a0a;color:#fff;font-family:sans-serif;text-align:center;padding:60px 20px"><h2 style="color:#d4af37">MC Training</h2><p style="color:#9ca3af;margin-top:12px">You are offline. Open this page while online to cache it.</p><a href="/" style="display:inline-block;margin-top:20px;color:#d4af37">← Home</a></body></html>',
        { headers: { 'Content-Type': 'text/html' } }
    );
}

// Stale-while-revalidate (audit LS-4, finding W-12). Serve the cached copy
// INSTANTLY when we have one — repeat navigations and the ~25 module loads per
// workout page feel instant instead of waiting on flaky gym Wi-Fi every time —
// and refresh the cache in the background for next load.
//
// Why cache-first is correct here (not stale): this is a static site whose
// HTML/JS/CSS only ever changes with a deploy, and every deploy bumps
// CACHE_NAME. The `activate` handler above purges the old cache, and
// mc-sw-update.js reloads the page on `controllerchange` (guarded against
// mid-workout). So a new build always reaches the user via the SW-version path,
// while within a single version the cache is byte-for-byte what the server
// would send — making cache-first both instant AND fresh. First visits (nothing
// cached yet) fall through to the network, with an offline fallback.
//
// Returns { response, revalidation } so the fetch handler can respondWith the
// response and waitUntil the revalidation (keeping the SW alive to finish the
// background cache write). Split out as a pure function so tools/test-mc-sw.js
// can verify the logic with a sandboxed fetch/caches — the live fetch handler
// is guarded to the production origin and can't be exercised on localhost.
function staleWhileRevalidate(request, offlineFallback) {
    const revalidation = fetch(request).then(resp => {
        if (resp && resp.status === 200) {
            const clone = resp.clone();
            caches.open(CACHE_NAME).then(c => c.put(request, clone));
        }
        return resp;
    }).catch(() => null);
    const response = caches.match(request).then(cached =>
        cached || revalidation.then(resp => resp || offlineFallback())
    );
    return { response, revalidation };
}

// Fetch — stale-while-revalidate for both navigations and assets.
self.addEventListener('fetch', event => {
    const url = event.request.url;

    // Only handle same-origin GETs (POSTs, Supabase calls, etc. pass through).
    if (!url.startsWith('https://mcross2298.github.io')) return;
    if (event.request.method !== 'GET') return;

    const isHTML = url.endsWith('.html') || url.endsWith('/') || !url.split('/').pop().includes('.');
    const { response, revalidation } = staleWhileRevalidate(
        event.request, isHTML ? offlinePage : assetOfflinePage
    );
    event.waitUntil(revalidation.catch(() => {}));
    event.respondWith(response);
});

// Push — show notification from server-sent milestone alert
self.addEventListener('push', event => {
    let title = 'MC Training', body = 'You have a new milestone!', icon = './icon.svg';
    try {
        if (event.data) {
            const d = event.data.json();
            if (d.title) title = d.title;
            if (d.body)  body  = d.body;
            if (d.icon)  icon  = d.icon;
        }
    } catch (_) {}
    event.waitUntil(
        self.registration.showNotification(title, {
            body,
            icon,
            badge: './icon.svg',
            tag: 'mc-milestone',
            renotify: true
        })
    );
});

// Notification click — open the dashboard
self.addEventListener('notificationclick', event => {
    event.notification.close();
    event.waitUntil(
        clients.matchAll({ type: 'window', includeUncontrolled: true }).then(list => {
            const dash = list.find(c => c.url.includes('dashboard.html'));
            if (dash) return dash.focus();
            return clients.openWindow('./dashboard.html');
        })
    );
});

// Message — force update
self.addEventListener('message', event => {
    if (event.data === 'skipWaiting') self.skipWaiting();
});